-- Records of config_info
-- ----------------------------
INSERT INTO `config_info` VALUES (1, 'application-dev.yml', 'DEFAULT_GROUP', 'spring:\n  cache:\n    type: redis\n  data:\n    redis:\n      host: ${REDIS_HOST:127.0.0.1}\n      port: ${REDIS_PORT:36379}\n      database: ${REDIS_DATABASE:0}\n  rabbitmq:\n    host: localhost \n    port: 5672\n    username: user\n    password: 123456\n    virtual-host: /\n    connection-timeout: 5000\n  cloud:\n    nacos:\n      server-addr: localhost:8848\n      username: nacos\n      password: nacos\n    sentinel:\n      eager: true\n      enabled: true\n      transport:\n        dashboard: localhost:8858\n    openfeign:\n      sentinel:\n        enabled: true\n      okhttp:\n        enabled: true\n      httpclient:\n        enabled: false\n      compression:\n        request:\n          enabled: true\n        response:\n          enabled: true\n    # seata:\n    #   enabled: true  # 启用开关\n    #   application-id: ${spring.application.name}  # 应用ID\n    #   tx-service-group: campus_tx_group  # 事务分组（必须）\n    datasource:\n      flow:\n        nacos:\n          server-addr: localhost:8848\n          username: nacos\n          password: nacos\n          data-id: ${spring.application.name}-flow-rules.json\n          group-id: SENTINEL_GROUP\n          data-type: json\n          rule-type: flow\n      degrade:\n        nacos:\n          server-addr: localhost:8848\n          username: nacos\n          password: nacos\n          data-id: ${spring.application.name}-degrade-rules.json\n          group-id: SENTINEL_GROUP\n          data-type: json\n          rule-type: degrade\n\n# 暴露监控端点\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \"*\"  \n  endpoint:\n    health:\n      show-details: ALWAYS\n\n# mybaits-plus配置\nmybatis-plus:\n  mapper-locations: classpath:/mapper/*Mapper.xml\n  global-config:\n    banner: false\n    db-config:\n      id-type: auto\n      table-underline: true\n      logic-delete-value: \'now()\'\n      logic-not-delete-value: \'null\'\n  type-handlers-package: com.example.common.mybatis.handler\n  configuration:\n    map-underscore-to-camel-case: true\n    shrink-whitespaces-in-sql: true\n\n# 短信插件配置：https://www.yuque.com/vxixfq/pig/zw8udk 暂时冗余\nsms:\n  is-print: false # 是否打印日志\n  config-type: yaml # 配置类型，yaml\n\nsecurity:\n  cors:\n    enabled: true\n    allowed-origin-patterns:\n      - \"*\"\n    allowed-headers:\n      - \"*\"\n    allowed-methods:\n      - GET\n      - POST\n      - PUT\n      - DELETE\n      - OPTIONS\n      - PATCH\n    allow-credentials: true\n    path-pattern: \"/**\"\n  oauth2:\n    ignore:\n      urls:\n        # 客户端详情查询\n        - /client/**\n        # 文件\n        - /files/**\n        # 其他内部服务接口\n\n# 日志配置（开发环境详细日志）\nlogging:\n  level:\n    com.example.campusapp: debug\n    org.springframework.security: debug\n\n', '80b8b7e04b78a805dfe62e80200e3996', '2026-01-15 11:12:50', '2026-02-28 17:51:53', 'nacos_namespace_migrate', '172.18.0.1', '', '', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (2, 'application-dev.yml', 'DEFAULT_GROUP', 'spring:\n  cache:\n    type: redis\n  data:\n    redis:\n      host: ${REDIS_HOST:127.0.0.1}\n      port: ${REDIS_PORT:36379}\n      database: ${REDIS_DATABASE:0}\n  rabbitmq:\n    host: localhost \n    port: 5672\n    username: user\n    password: 123456\n    virtual-host: /\n    connection-timeout: 5000\n  cloud:\n    nacos:\n      server-addr: localhost:8848\n      username: nacos\n      password: nacos\n    sentinel:\n      eager: true\n      enabled: true\n      transport:\n        dashboard: localhost:8858\n    openfeign:\n      sentinel:\n        enabled: true\n      okhttp:\n        enabled: true\n      httpclient:\n        enabled: false\n      compression:\n        request:\n          enabled: true\n        response:\n          enabled: true\n    # seata:\n    #   enabled: true  # 启用开关\n    #   application-id: ${spring.application.name}  # 应用ID\n    #   tx-service-group: campus_tx_group  # 事务分组（必须）\n    datasource:\n      flow:\n        nacos:\n          server-addr: localhost:8848\n          username: nacos\n          password: nacos\n          data-id: ${spring.application.name}-flow-rules.json\n          group-id: SENTINEL_GROUP\n          data-type: json\n          rule-type: flow\n      degrade:\n        nacos:\n          server-addr: localhost:8848\n          username: nacos\n          password: nacos\n          data-id: ${spring.application.name}-degrade-rules.json\n          group-id: SENTINEL_GROUP\n          data-type: json\n          rule-type: degrade\n\n# 暴露监控端点\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \"*\"  \n  endpoint:\n    health:\n      show-details: ALWAYS\n\n# mybaits-plus配置\nmybatis-plus:\n  mapper-locations: classpath:/mapper/*Mapper.xml\n  global-config:\n    banner: false\n    db-config:\n      id-type: auto\n      table-underline: true\n      logic-delete-value: \'now()\'\n      logic-not-delete-value: \'null\'\n  type-handlers-package: com.example.common.mybatis.handler\n  configuration:\n    map-underscore-to-camel-case: true\n    shrink-whitespaces-in-sql: true\n\n# 短信插件配置：https://www.yuque.com/vxixfq/pig/zw8udk 暂时冗余\nsms:\n  is-print: false # 是否打印日志\n  config-type: yaml # 配置类型，yaml\n\nsecurity:\n  cors:\n    enabled: true\n    allowed-origin-patterns:\n      - \"*\"\n    allowed-headers:\n      - \"*\"\n    allowed-methods:\n      - GET\n      - POST\n      - PUT\n      - DELETE\n      - OPTIONS\n      - PATCH\n    allow-credentials: true\n    path-pattern: \"/**\"\n  oauth2:\n    ignore:\n      urls:\n        # 客户端详情查询\n        - /client/**\n        # 文件\n        - /files/**\n        # 其他内部服务接口\n\n# 日志配置（开发环境详细日志）\nlogging:\n  level:\n    com.example.campusapp: debug\n    org.springframework.security: debug\n\n', '80b8b7e04b78a805dfe62e80200e3996', '2026-01-15 11:12:50', '2026-02-28 17:51:54', 'nacos', '172.18.0.1', '', 'public', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (3, 'campus-auth-dev.yml', 'DEFAULT_GROUP', 'spring:\n  datasource:\n    type: com.zaxxer.hikari.HikariDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    username: ${MYSQL_USERNAME}\n    password: ${MYSQL_PASSWORD}\n    url: jdbc:mysql://${MYSQL_HOST:106.13.143.56}:${MYSQL_PORT:3306}/${MYSQL_UPMS_DB:campus_upms_db}?characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=false&allowMultiQueries=true&useJDBCCompliantTimezoneShift=true&useLegacyDatetimeCode=false&serverTimezone=Asia/Shanghai&nullCatalogMeansCurrent=true&allowPublicKeyRetrieval=true\n\nsecurity:\n  encode-key: \'admin1234567890a\'\n  ignore-clients:\n    - app\n    - campus\n    - miniapp\n', '83538e4fa7c7c57a0f70923f6368cd20', '2026-01-15 11:13:05', '2026-02-10 17:46:34', 'nacos_namespace_migrate', '172.18.0.1', '', '', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (4, 'campus-auth-dev.yml', 'DEFAULT_GROUP', 'spring:\n  datasource:\n    type: com.zaxxer.hikari.HikariDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    username: ${MYSQL_USERNAME}\n    password: ${MYSQL_PASSWORD}\n    url: jdbc:mysql://${MYSQL_HOST:106.13.143.56}:${MYSQL_PORT:3306}/${MYSQL_UPMS_DB:campus_upms_db}?characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=false&allowMultiQueries=true&useJDBCCompliantTimezoneShift=true&useLegacyDatetimeCode=false&serverTimezone=Asia/Shanghai&nullCatalogMeansCurrent=true&allowPublicKeyRetrieval=true\n\nsecurity:\n  encode-key: \'admin1234567890a\'\n  ignore-clients:\n    - app\n    - campus\n    - miniapp\n', '83538e4fa7c7c57a0f70923f6368cd20', '2026-01-15 11:13:06', '2026-02-10 17:46:34', 'nacos', '172.18.0.1', '', 'public', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (5, 'campus-gateway-dev.yml', 'DEFAULT_GROUP', 'spring:\n  cloud:\n    gateway:\n      default-filters:\n      - DedupeResponseHeader=Access-Control-Allow-Origin\n      globalcors:\n        cors-configurations:\n          \'[/**]\':\n            allowedOriginPatterns: \"*\"           #注意这个设置只对 spring boot 2.4+ 有效，低版本 使用  allowedOrigins: \"*\" 属性\n            allowed-methods: \"*\"\n            allowed-headers: \"*\"\n            allow-credentials: true\n            exposedHeaders: \"Content-Disposition,Content-Type,Cache-Control\"\n\n      server:\n        webflux:\n          routes:\n            # 认证中心\n            - id: campus-auth\n              uri: lb://campus-auth\n              predicates:\n                - Path=/auth/**\n              filters:\n                - RewritePath=/auth/(?<segment>.*), /${segment}\n            \n            # UPMS 模块\n            - id: campus-upms-biz \n              uri: lb://upms-biz \n              predicates: \n                - Path=/admin/** \n              filters: \n                - name: RequestRateLimiter \n                  args: \n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \n                    redis-rate-limiter.replenishRate: 100 \n                    redis-rate-limiter.burstCapacity: 200\n                - RewritePath=/admin/(?<path>.*), /$\\{path}\n\n            # message 模块\n            - id: campus-message-biz \n              uri: lb://message-biz \n              predicates: \n                - Path=/message/** \n              filters: \n                - name: RequestRateLimiter \n                  args: \n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \n                    redis-rate-limiter.replenishRate: 100 \n                    redis-rate-limiter.burstCapacity: 200\n                - RewritePath=/message/(?<path>.*), /$\\{path}\n\n            # order 模块\n            - id: campus-order-biz \n              uri: lb://order-biz \n              predicates: \n                - Path=/order/** \n              filters: \n                - name: RequestRateLimiter \n                  args: \n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \n                    redis-rate-limiter.replenishRate: 100 \n                    redis-rate-limiter.burstCapacity: 200\n                - RewritePath=/order/(?<path>.*), /$\\{path}\n               # forum 模块\n            - id: campus-forum-biz \n              uri: lb://forum-biz \n              predicates: \n                - Path=/forum/** \n              filters: \n                - name: RequestRateLimiter \n                  args: \n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \n                    redis-rate-limiter.replenishRate: 100 \n                    redis-rate-limiter.burstCapacity: 200\n                - RewritePath=/forum/(?<path>.*), /$\\{path}\n\n               # behavior 模块\n            - id: campus-behavior-biz \n              uri: lb://campus-behavior \n              predicates: \n                - Path=/behavior/** \n              filters: \n                - name: RequestRateLimiter \n                  args: \n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \n                    redis-rate-limiter.replenishRate: 100 \n                    redis-rate-limiter.burstCapacity: 200\n                - RewritePath=/behavior/(?<path>.*), /$\\{path}\n\n               # finance 模块\n            - id: campus-finance-biz \n              uri: lb://finance-biz \n              predicates: \n                - Path=/finance/** \n              filters: \n                - name: RequestRateLimiter \n                  args: \n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \n                    redis-rate-limiter.replenishRate: 100 \n                    redis-rate-limiter.burstCapacity: 200\n                - RewritePath=/finance/(?<path>.*), /$\\{path}\n\n               # merchant 模块\n            - id: campus-merchant-biz \n              uri: lb://merchant-biz \n              predicates: \n                - Path=/merchant/** \n              filters: \n                - name: RequestRateLimiter \n                  args: \n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \n                    redis-rate-limiter.replenishRate: 100 \n                    redis-rate-limiter.burstCapacity: 200\n                - RewritePath=/merchant/(?<path>.*), /$\\{path}\n\n               # service 模块\n            - id: campus-service-biz \n              uri: lb://service-biz \n              predicates: \n                - Path=/service/** \n              filters: \n                - name: RequestRateLimiter \n                  args: \n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \n                    redis-rate-limiter.replenishRate: 100 \n                    redis-rate-limiter.burstCapacity: 200\n                - RewritePath=/service/(?<path>.*), /$\\{path}\n  \n            # 固定路由转发配置\n            - id: openapi\n              uri: lb://campus-gateway\n              predicates:\n                - Path=/v3/api-docs/**\n              filters:\n                - RewritePath=/v3/api-docs/(?<path>.*), /$\\{path}/$\\{path}/v3/api-docs\n\n', 'c5bb9191849e28637033c2b1b3279ddd', '2026-01-15 11:13:17', '2026-01-31 09:20:54', 'nacos_namespace_migrate', '172.18.0.1', '', '', '', NULL, NULL, 'yaml', NULL, '');
