    predicates: \n                - Path=/order/** \n              filters: \n                - name: RequestRateLimiter \n                  args: \n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \n                    redis-rate-limiter.replenishRate: 100 \n                    redis-rate-limiter.burstCapacity: 200\n                - RewritePath=/order/(?<path>.*), /$\\{path}\n               # forum 模块\n            - id: campus-forum-biz \n              uri: lb://forum-biz \n              predicates: \n                - Path=/forum/** \n              filters: \n                - name: RequestRateLimiter \n                  args: \n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \n                    redis-rate-limiter.replenishRate: 100 \n                    redis-rate-limiter.burstCapacity: 200\n                - RewritePath=/forum/(?<path>.*), /$\\{path}\n\n               # behavior 模块\n            - id: campus-behavior-biz \n              uri: lb://campus-behavior \n              predicates: \n                - Path=/behavior/** \n              filters: \n                - name: RequestRateLimiter \n                  args: \n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \n                    redis-rate-limiter.replenishRate: 100 \n                    redis-rate-limiter.burstCapacity: 200\n                - RewritePath=/behavior/(?<path>.*), /$\\{path}\n\n               # finance 模块\n            - id: campus-finance-biz \n              uri: lb://finance-biz \n              predicates: \n                - Path=/finance/** \n              filters: \n                - name: RequestRateLimiter \n                  args: \n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \n                    redis-rate-limiter.replenishRate: 100 \n                    redis-rate-limiter.burstCapacity: 200\n                - RewritePath=/finance/(?<path>.*), /$\\{path}\n\n               # merchant 模块\n            - id: campus-merchant-biz \n              uri: lb://merchant-biz \n              predicates: \n                - Path=/merchant/** \n              filters: \n                - name: RequestRateLimiter \n                  args: \n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \n                    redis-rate-limiter.replenishRate: 100 \n                    redis-rate-limiter.burstCapacity: 200\n                - RewritePath=/merchant/(?<path>.*), /$\\{path}\n\n               # service 模块\n            - id: campus-service-biz \n              uri: lb://service-biz \n              predicates: \n                - Path=/service/** \n              filters: \n                - name: RequestRateLimiter \n                  args: \n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \n                    redis-rate-limiter.replenishRate: 100 \n                    redis-rate-limiter.burstCapacity: 200\n                - RewritePath=/service/(?<path>.*), /$\\{path}\n  \n            # 固定路由转发配置\n            - id: openapi\n              uri: lb://campus-gateway\n              predicates:\n                - Path=/v3/api-docs/**\n              filters:\n                - RewritePath=/v3/api-docs/(?<path>.*), /$\\{path}/$\\{path}/v3/api-docs\n\n', 'c5bb9191849e28637033c2b1b3279ddd', '2026-01-15 11:13:17', '2026-01-31 09:20:54', 'nacos', '172.18.0.1', '', 'public', '', NULL, NULL, 'yaml', NULL, '');
