INSERT INTO `config_info` VALUES (38, 'saas-gateway-dev.yml', 'DEFAULT_GROUP', 'spring:\n  cloud:\n    gateway:\n      server:\n        webflux:\n          default-filters:\n            - DedupeResponseHeader=Access-Control-Allow-Origin\n          globalcors:\n            cors-configurations:\n              \'[/**]\':\n                allowedOriginPatterns: \"*\"           #注意这个设置只对 spring boot 2.4+ 有效，低版本 使用  allowedOrigins: \"*\" 属性\n                allowed-methods: \"*\"\n                allowed-headers: \"*\"\n                allow-credentials: true\n                exposedHeaders: \"Content-Disposition,Content-Type,Cache-Control\"\n          routes:\n            # 认证中心\n            - id: saas-auth\n              uri: lb://saas-auth\n              predicates:\n                - Path=/auth/**\n              filters:\n                - RewritePath=/auth/(?<segment>.*), /${segment}\n            \n            # UPMS 模块\n            - id: saas-upms-biz \n              uri: lb://saas-upms-biz \n              predicates: \n                - Path=/admin/** \n              filters: \n                - name: RequestRateLimiter \n                  args: \n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \n                    redis-rate-limiter.replenishRate: 100 \n                    redis-rate-limiter.burstCapacity: 200\n                - RewritePath=/admin/(?<path>.*), /$\\{path}\n\n            # file 模块\n            - id: saas-file\n              uri: lb://saas-file\n              predicates: \n                - Path=/file/** \n              filters: \n                - name: RequestRateLimiter \n                  args: \n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \n                    redis-rate-limiter.replenishRate: 100 \n                    redis-rate-limiter.burstCapacity: 200\n                - RewritePath=/file/(?<path>.*), /$\\{path}\n\n            # service 模块\n            - id: saas-service-biz \n              uri: lb://saas-service-biz \n              predicates: \n                - Path=/service/** \n              filters: \n                - name: RequestRateLimiter \n                  args: \n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \n                    redis-rate-limiter.replenishRate: 100 \n                    redis-rate-limiter.burstCapacity: 200\n                - RewritePath=/service/(?<path>.*), /$\\{path}\n\n  \n            # 固定路由转发配置\n            - id: openapi\n              uri: lb://saas-gateway\n              predicates:\n                - Path=/v3/api-docs/**\n              filters:\n                - RewritePath=/v3/api-docs/(?<path>.*), /$\\{path}/$\\{path}/v3/api-docs\n\n', '0f02c63f2099a89ad233223b0d24a15f', '2026-02-16 07:30:38', '2026-02-18 21:56:06', 'nacos', '172.18.0.1', '', 'saas', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (39, 'saas-upms-biz-dev.yml', 'DEFAULT_GROUP', 'spring:\r\n  datasource:\r\n    type: com.zaxxer.hikari.HikariDataSource\r\n    driver-class-name: com.mysql.cj.jdbc.Driver\r\n    username: ${MYSQL_USERNAME}\r\n    password: ${MYSQL_PASSWORD}\r\n    url: jdbc:mysql://${MYSQL_HOST:106.13.143.56}:${MYSQL_PORT:3306}/${GLOBAL_DATABASE:sass_global}?characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=false&allowMultiQueries=true&useJDBCCompliantTimezoneShift=true&useLegacyDatetimeCode=false&serverTimezone=Asia/Shanghai&nullCatalogMeansCurrent=true&allowPublicKeyRetrieval=true\r\n', '529f353552bd5c0c17d0fd3e833529cd', '2026-02-16 07:30:54', '2026-02-16 07:30:54', 'nacos', '172.18.0.1', '', 'saas', NULL, NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (40, 'application-dev.yml', 'DEFAULT_GROUP', 'spring:\n  cache:\n    type: redis\n  data:\n    redis:\n      host: ${REDIS_HOST:127.0.0.1}\n      password: ${REDIS_PASSWORD:}\n      port: ${REDIS_PORT:36379}\n      database: ${REDIS_DATABASE:0}\n  cloud:\n    nacos:\n      server-addr: localhost:8848\n      username: nacos\n      password: nacos\n    sentinel:\n      eager: true\n      enabled: true\n      transport:\n        dashboard: localhost:8858\n    openfeign:\n      sentinel:\n        enabled: true\n      okhttp:\n        enabled: true\n      httpclient:\n        enabled: false\n      compression:\n        request:\n          enabled: true\n        response:\n          enabled: true\n    # seata:\n    #   enabled: true  # 启用开关\n    #   application-id: ${spring.application.name}  # 应用ID\n    #   tx-service-group: campus_tx_group  # 事务分组（必须）\n\n# 暴露监控端点\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \"*\"  \n  endpoint:\n    health:\n      show-details: ALWAYS\n\n# mybaits-plus配置\nmybatis-plus:\n  mapper-locations: classpath:/mapper/*Mapper.xml\n  global-config:\n    banner: false\n    db-config:\n      id-type: auto\n      table-underline: true\n      logic-delete-value: \'now()\'\n      logic-not-delete-value: \'null\'\n  type-handlers-package: com.example.common.mybatis.handler\n  configuration:\n    map-underscore-to-camel-case: true\n    shrink-whitespaces-in-sql: true\n\n\nsecurity:\n  cors:\n    enabled: true\n    allowed-origin-patterns:\n      - \"*\"\n    allowed-headers:\n      - \"*\"\n    allowed-methods:\n      - GET\n      - POST\n      - PUT\n      - DELETE\n      - OPTIONS\n      - PATCH\n    allow-credentials: true\n    path-pattern: \"/**\"\n  oauth2:\n    ignore:\n      urls:\n        # 客户端详情查询\n        - /client/**\n        # 文件\n        - /files/**\n        # 登录页配置\n        - /config/admin\n        # 其他内部服务接口\n\n# 日志配置（开发环境详细日志）\nlogging:\n  level:\n    com.example.campusapp: debug\n    org.springframework.security: debug\n\n', '82e53a06bf9dc3d09b98bfd170cc1080', '2026-02-16 07:31:09', '2026-02-16 20:30:34', 'nacos', '172.18.0.1', '', 'saas', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (41, 'saas-auth-dev.yml', 'DEFAULT_GROUP', 'spring:\r\n  datasource:\r\n    type: com.zaxxer.hikari.HikariDataSource\r\n    driver-class-name: com.mysql.cj.jdbc.Driver\r\n    username: ${MYSQL_USERNAME}\r\n    password: ${MYSQL_PASSWORD}\r\n    url: jdbc:mysql://${MYSQL_HOST:106.13.143.56}:${MYSQL_PORT:3306}/${GLOBAL_DATABASE:sass_global}?characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=false&allowMultiQueries=true&useJDBCCompliantTimezoneShift=true&useLegacyDatetimeCode=false&serverTimezone=Asia/Shanghai&nullCatalogMeansCurrent=true&allowPublicKeyRetrieval=true\r\n\r\nsecurity:\r\n  ignore-clients:\r\n    - sass\r\n', '9261796a10928f2373e5e4b85ee17209', '2026-02-16 07:31:26', '2026-02-16 07:31:26', 'nacos', '172.18.0.1', '', 'saas', NULL, NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (43, 'saas-file-dev.yml', 'DEFAULT_GROUP', 'spring:\n  datasource:\n    type: com.zaxxer.hikari.HikariDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    username: ${MYSQL_USERNAME}\n    password: ${MYSQL_PASSWORD}\n    url: jdbc:mysql://${MYSQL_HOST:106.13.143.56}:${MYSQL_PORT:3306}/${GLOBAL_DATABASE:sass_global}?characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=false&allowMultiQueries=true&useJDBCCompliantTimezoneShift=true&useLegacyDatetimeCode=false&serverTimezone=Asia/Shanghai&nullCatalogMeansCurrent=true&allowPublicKeyRetrieval=true\n\n  servlet:\n    multipart:\n      max-file-size: 100MB\n      max-request-size: 100MB\n# 文件存储配置\nfile:\n  storage:\n    type: local\n    local:\n      base-path: ${FILE_STORAGE_PATH:./data/upload/files}\n      url-prefix: ${FILE_URL_PREFIX:http://localhost:4001/files}\n    allowed-types:\n      - image/jpeg\n      - image/png\n      - image/gif\n      - image/webp\n      - image/svg+xml\n      - application/pdf\n      - application/msword\n      - application/vnd.openxmlformats-officedocument.wordprocessingml.document\n      - application/vnd.ms-excel\n      - application/vnd.openxmlformats-officedocument.spreadsheetml.sheet\n      - text/plain\n      - application/zip\n      - application/x-rar-compressed\n      - application/x-pem-file  # 标准 PEM 类型\n      - application/octet-stream # 二进制流\n      - application/x-x509-ca-cert\n      - text/plain               # 纯文本\n    max-size: 104857600', '3cc8838b41edc2fca2e419fb1a67cd75', '2026-02-16 07:32:08', '2026-02-17 18:51:32', 'nacos', '172.18.0.1', '', 'saas', '', NULL, NULL, 'yaml', NULL, '');
