INSERT INTO `his_config_info` VALUES (36, 113, 'sass-auth-dev.yml', 'DEFAULT_GROUP', '', 'spring:\r\n  datasource:\r\n    type: com.zaxxer.hikari.HikariDataSource\r\n    driver-class-name: com.mysql.cj.jdbc.Driver\r\n    username: ${MYSQL_USERNAME}\r\n    password: ${MYSQL_PASSWORD}\r\n    url: jdbc:mysql://${MYSQL_HOST:106.13.143.56}:${MYSQL_PORT:3306}/${GLOBAL_DATABASE:sass-global}?characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=false&allowMultiQueries=true&useJDBCCompliantTimezoneShift=true&useLegacyDatetimeCode=false&serverTimezone=Asia/Shanghai&nullCatalogMeansCurrent=true&allowPublicKeyRetrieval=true\r\n\r\nsecurity:\r\n  ignore-clients:\r\n    - sass\r\n', 'd8aa739c2cbf240f224e2f5ab53d61ba', '2026-02-14 21:43:45', '2026-02-14 21:43:45', 'nacos', '172.18.0.1', 'U', 'sass', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');
INSERT INTO `his_config_info` VALUES (32, 114, 'sass-gateway-dev.yml', 'DEFAULT_GROUP', '', 'spring:\r\n  cloud:\r\n    gateway:\r\n      default-filters:\r\n      - DedupeResponseHeader=Access-Control-Allow-Origin\r\n      globalcors:\r\n        cors-configurations:\r\n          \'[/**]\':\r\n            allowedOriginPatterns: \"*\"           #注意这个设置只对 spring boot 2.4+ 有效，低版本 使用  allowedOrigins: \"*\" 属性\r\n            allowed-methods: \"*\"\r\n            allowed-headers: \"*\"\r\n            allow-credentials: true\r\n            exposedHeaders: \"Content-Disposition,Content-Type,Cache-Control\"\r\n\r\n      server:\r\n        webflux:\r\n          routes:\r\n            # 认证中心\r\n            - id: campus-auth\r\n              uri: lb://campus-auth\r\n              predicates:\r\n                - Path=/auth/**\r\n              filters:\r\n                - RewritePath=/auth/(?<segment>.*), /${segment}\r\n            \r\n            # UPMS 模块\r\n            - id: campus-upms-biz \r\n              uri: lb://upms-biz \r\n              predicates: \r\n                - Path=/admin/** \r\n              filters: \r\n                - name: RequestRateLimiter \r\n                  args: \r\n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \r\n                    redis-rate-limiter.replenishRate: 100 \r\n                    redis-rate-limiter.burstCapacity: 200\r\n                - RewritePath=/admin/(?<path>.*), /$\\{path}\r\n\r\n  \r\n            # 固定路由转发配置\r\n            - id: openapi\r\n              uri: lb://campus-gateway\r\n              predicates:\r\n                - Path=/v3/api-docs/**\r\n              filters:\r\n                - RewritePath=/v3/api-docs/(?<path>.*), /$\\{path}/$\\{path}/v3/api-docs\r\n\r\n', '4c3eddbfa2d4db80efa550cc40ee2282', '2026-02-14 21:45:14', '2026-02-14 21:45:14', 'nacos', '172.18.0.1', 'U', 'sass', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');
