INSERT INTO `his_config_info` VALUES (35, 118, 'application-dev.yml', 'DEFAULT_GROUP', '', 'spring:\r\n  cache:\r\n    type: redis\r\n  data:\r\n    redis:\r\n      host: ${REDIS_HOST:127.0.0.1}\r\n      password: ${REDIS_PASSWORD:}\r\n      port: ${REDIS_PORT:36379}\r\n      database: ${REDIS_DATABASE:0}\r\n  cloud:\r\n    nacos:\r\n      server-addr: localhost:8848\r\n      username: nacos\r\n      password: nacos\r\n    sentinel:\r\n      eager: true\r\n      enabled: true\r\n      transport:\r\n        dashboard: localhost:8858\r\n    openfeign:\r\n      sentinel:\r\n        enabled: true\r\n      okhttp:\r\n        enabled: true\r\n      httpclient:\r\n        enabled: false\r\n      compression:\r\n        request:\r\n          enabled: true\r\n        response:\r\n          enabled: true\r\n    # seata:\r\n    #   enabled: true  # 启用开关\r\n    #   application-id: ${spring.application.name}  # 应用ID\r\n    #   tx-service-group: campus_tx_group  # 事务分组（必须）\r\n\r\n# 暴露监控端点\r\nmanagement:\r\n  endpoints:\r\n    web:\r\n      exposure:\r\n        include: \"*\"  \r\n  endpoint:\r\n    health:\r\n      show-details: ALWAYS\r\n\r\n# mybaits-plus配置\r\nmybatis-plus:\r\n  mapper-locations: classpath:/mapper/*Mapper.xml\r\n  global-config:\r\n    banner: false\r\n    db-config:\r\n      id-type: auto\r\n      table-underline: true\r\n      logic-delete-value: \'now()\'\r\n      logic-not-delete-value: \'null\'\r\n  type-handlers-package: com.example.common.mybatis.handler\r\n  configuration:\r\n    map-underscore-to-camel-case: true\r\n    shrink-whitespaces-in-sql: true\r\n\r\n\r\nsecurity:\r\n  cors:\r\n    enabled: true\r\n    allowed-origin-patterns:\r\n      - \"*\"\r\n    allowed-headers:\r\n      - \"*\"\r\n    allowed-methods:\r\n      - GET\r\n      - POST\r\n      - PUT\r\n      - DELETE\r\n      - OPTIONS\r\n      - PATCH\r\n    allow-credentials: true\r\n    path-pattern: \"/**\"\r\n  oauth2:\r\n    ignore:\r\n      urls:\r\n        # 客户端详情查询\r\n        - /client/**\r\n        # 文件\r\n        - /files/**\r\n        # 其他内部服务接口\r\n\r\n# 日志配置（开发环境详细日志）\r\nlogging:\r\n  level:\r\n    com.example.campusapp: debug\r\n    org.springframework.security: debug\r\n\r\n', '62b5f2bb745ce414ba6615f8d041b413', '2026-02-15 12:39:39', '2026-02-15 12:39:40', 'nacos', '172.18.0.1', 'U', 'sass', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');
