/sass-gateway\n              predicates:\n                - Path=/v3/api-docs/**\n              filters:\n                - RewritePath=/v3/api-docs/(?<path>.*), /$\\{path}/$\\{path}/v3/api-docs\n\n', '2a27a1ebfb9ef687ce2336a6846a4e03', '2026-02-16 07:32:57', '2026-02-16 07:32:58', 'nacos', '172.18.0.1', 'D', 'sass', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');
