INSERT INTO `his_config_info` VALUES (37, 137, 'sass-file-dev.yml', 'DEFAULT_GROUP', '', 'spring:\n  datasource:\n    type: com.zaxxer.hikari.HikariDataSource\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    username: ${MYSQL_USERNAME}\n    password: ${MYSQL_PASSWORD}\n    url: jdbc:mysql://${MYSQL_HOST:106.13.143.56}:${MYSQL_PORT:3306}/${GLOBAL_DATABASE:sass_global}?characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=false&allowMultiQueries=true&useJDBCCompliantTimezoneShift=true&useLegacyDatetimeCode=false&serverTimezone=Asia/Shanghai&nullCatalogMeansCurrent=true&allowPublicKeyRetrieval=true\n\n  servlet:\n    multipart:\n      max-file-size: 100MB\n      max-request-size: 100MB\n# 文件存储配置\nfile:\n  storage:\n    type: local\n    local:\n      base-path: ${FILE_STORAGE_PATH:./data/upload/files}\n      url-prefix: ${FILE_URL_PREFIX:http://localhost:4001/files}\n    allowed-types:\n      - image/jpeg\n      - image/png\n      - image/gif\n      - image/webp\n      - image/svg+xml\n      - application/pdf\n      - application/msword\n      - application/vnd.openxmlformats-officedocument.wordprocessingml.document\n      - application/vnd.ms-excel\n      - application/vnd.openxmlformats-officedocument.spreadsheetml.sheet\n      - text/plain\n      - application/zip\n      - application/x-rar-compressed\n    max-size: 104857600', '650e485089c6d86188643c44e1d636b7', '2026-02-16 07:33:04', '2026-02-16 07:33:05', 'nacos', '172.18.0.1', 'D', 'sass', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');
INSERT INTO `his_config_info` VALUES (38, 138, 'saas-gateway-dev.yml', 'DEFAULT_GROUP', '', 'spring:\r\n  cloud:\r\n    gateway:\r\n      server:\r\n        webflux:\r\n          default-filters:\r\n            - DedupeResponseHeader=Access-Control-Allow-Origin\r\n          globalcors:\r\n            cors-configurations:\r\n              \'[/**]\':\r\n                allowedOriginPatterns: \"*\"           #注意这个设置只对 spring boot 2.4+ 有效，低版本 使用  allowedOrigins: \"*\" 属性\r\n                allowed-methods: \"*\"\r\n                allowed-headers: \"*\"\r\n                allow-credentials: true\r\n                exposedHeaders: \"Content-Disposition,Content-Type,Cache-Control\"\r\n          routes:\r\n            # 认证中心\r\n            - id: sass-auth\r\n              uri: lb://sass-auth\r\n              predicates:\r\n                - Path=/auth/**\r\n              filters:\r\n                - RewritePath=/auth/(?<segment>.*), /${segment}\r\n            \r\n            # UPMS 模块\r\n            - id: sass-upms-biz \r\n              uri: lb://sass-upms-biz \r\n              predicates: \r\n                - Path=/admin/** \r\n              filters: \r\n                - name: RequestRateLimiter \r\n                  args: \r\n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \r\n                    redis-rate-limiter.replenishRate: 100 \r\n                    redis-rate-limiter.burstCapacity: 200\r\n                - RewritePath=/admin/(?<path>.*), /$\\{path}\r\n\r\n            # file 模块\r\n            - id: sass-file\r\n              uri: lb://sass-file\r\n              predicates: \r\n                - Path=/file/** \r\n              filters: \r\n                - name: RequestRateLimiter \r\n                  args: \r\n                    key-resolver: \'#{@remoteAddrKeyResolver}\' \r\n                    redis-rate-limiter.replenishRate: 100 \r\n                    redis-rate-limiter.burstCapacity: 200\r\n                - RewritePath=/file/(?<path>.*), /$\\{path}\r\n\r\n  \r\n            # 固定路由转发配置\r\n            - id: openapi\r\n              uri: lb://sass-gateway\r\n              predicates:\r\n                - Path=/v3/api-docs/**\r\n              filters:\r\n                - RewritePath=/v3/api-docs/(?<path>.*), /$\\{path}/$\\{path}/v3/api-docs\r\n\r\n', 'edc9eb4b2d9d9a96a2a35253e6ae8e74', '2026-02-16 07:33:38', '2026-02-16 07:33:39', 'nacos', '172.18.0.1', 'U', 'saas', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');
INSERT INTO `his_config_info` VALUES (40, 139, 'application-dev.yml', 'DEFAULT_GROUP', '', 'spring:\r\n  cache:\r\n    type: redis\r\n  data:\r\n    redis:\r\n      host: ${REDIS_HOST:127.0.0.1}\r\n      password: ${REDIS_PASSWORD:}\r\n      port: ${REDIS_PORT:36379}\r\n      database: ${REDIS_DATABASE:0}\r\n  cloud:\r\n    nacos:\r\n      server-addr: localhost:8848\r\n      username: nacos\r\n      password: nacos\r\n    sentinel:\r\n      eager: true\r\n      enabled: true\r\n      transport:\r\n        dashboard: localhost:8858\r\n    openfeign:\r\n      sentinel:\r\n        enabled: true\r\n      okhttp:\r\n        enabled: true\r\n      httpclient:\r\n        enabled: false\r\n      compression:\r\n        request:\r\n          enabled: true\r\n        response:\r\n          enabled: true\r\n    # seata:\r\n    #   enabled: true  # 启用开关\r\n    #   application-id: ${spring.application.name}  # 应用ID\r\n    #   tx-service-group: campus_tx_group  # 事务分组（必须）\r\n\r\n# 暴露监控端点\r\nmanagement:\r\n  endpoints:\r\n    web:\r\n      exposure:\r\n        include: \"*\"  \r\n  endpoint:\r\n    health:\r\n      show-details: ALWAYS\r\n\r\n# mybaits-plus配置\r\nmybatis-plus:\r\n  mapper-locations: classpath:/mapper/*Mapper.xml\r\n  global-config:\r\n    banner: false\r\n    db-config:\r\n      id-type: auto\r\n      table-underline: true\r\n      logic-delete-value: \'now()\'\r\n      logic-not-delete-value: \'null\'\r\n  type-handlers-package: com.example.common.mybatis.handler\r\n  configuration:\r\n    map-underscore-to-camel-case: true\r\n    shrink-whitespaces-in-sql: true\r\n\r\n\r\nsecurity:\r\n  cors:\r\n    enabled: true\r\n    allowed-origin-patterns:\r\n      - \"*\"\r\n    allowed-headers:\r\n      - \"*\"\r\n    allowed-methods:\r\n      - GET\r\n      - POST\r\n      - PUT\r\n      - DELETE\r\n      - OPTIONS\r\n      - PATCH\r\n    allow-credentials: true\r\n    path-pattern: \"/**\"\r\n  oauth2:\r\n    ignore:\r\n      urls:\r\n        # 客户端详情查询\r\n        - /client/**\r\n        # 文件\r\n        - /files/**\r\n        # 登录页配置\r\n        - /config/admin\r\n        # 其他内部服务接口\r\n\r\n# 日志配置（开发环境详细日志）\r\nlogging:\r\n  level:\r\n    com.example.campusapp: debug\r\n    org.springframework.security: debug\r\n\r\n', '3ebcdb98865b02bb0e2b260718e78a4e', '2026-02-16 20:25:26', '2026-02-16 20:25:28', 'nacos', '172.18.0.1', 'U', 'saas', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');
