INSERT INTO `his_config_info` VALUES (2, 149, 'application-dev.yml', 'DEFAULT_GROUP', '', 'spring:\n  cache:\n    type: redis\n  data:\n    redis:\n      host: ${REDIS_HOST:127.0.0.1}\n      password: ${REDIS_PASSWORD:}\n      port: ${REDIS_PORT:36379}\n      database: ${REDIS_DATABASE:0}\n  cloud:\n    nacos:\n      server-addr: localhost:8848\n      username: nacos\n      password: nacos\n    sentinel:\n      eager: true\n      enabled: true\n      transport:\n        dashboard: localhost:8858\n    openfeign:\n      sentinel:\n        enabled: true\n      okhttp:\n        enabled: true\n      httpclient:\n        enabled: false\n      compression:\n        request:\n          enabled: true\n        response:\n          enabled: true\n    # seata:\n    #   enabled: true  # 启用开关\n    #   application-id: ${spring.application.name}  # 应用ID\n    #   tx-service-group: campus_tx_group  # 事务分组（必须）\n    datasource:\n      flow:\n        nacos:\n          server-addr: localhost:8848\n          username: nacos\n          password: nacos\n          data-id: ${spring.application.name}-flow-rules.json\n          group-id: SENTINEL_GROUP\n          data-type: json\n          rule-type: flow\n      degrade:\n        nacos:\n          server-addr: localhost:8848\n          username: nacos\n          password: nacos\n          data-id: ${spring.application.name}-degrade-rules.json\n          group-id: SENTINEL_GROUP\n          data-type: json\n          rule-type: degrade\n\n# 暴露监控端点\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \"*\"  \n  endpoint:\n    health:\n      show-details: ALWAYS\n\n# mybaits-plus配置\nmybatis-plus:\n  mapper-locations: classpath:/mapper/*Mapper.xml\n  global-config:\n    banner: false\n    db-config:\n      id-type: auto\n      table-underline: true\n      logic-delete-value: \'now()\'\n      logic-not-delete-value: \'null\'\n  type-handlers-package: com.example.common.mybatis.handler\n  configuration:\n    map-underscore-to-camel-case: true\n    shrink-whitespaces-in-sql: true\n\n# 短信插件配置：https://www.yuque.com/vxixfq/pig/zw8udk 暂时冗余\nsms:\n  is-print: false # 是否打印日志\n  config-type: yaml # 配置类型，yaml\n\nsecurity:\n  cors:\n    enabled: true\n    allowed-origin-patterns:\n      - \"*\"\n    allowed-headers:\n      - \"*\"\n    allowed-methods:\n      - GET\n      - POST\n      - PUT\n      - DELETE\n      - OPTIONS\n      - PATCH\n    allow-credentials: true\n    path-pattern: \"/**\"\n  oauth2:\n    ignore:\n      urls:\n        # 客户端详情查询\n        - /client/**\n        # 文件\n        - /files/**\n        # 其他内部服务接口\n\n# 日志配置（开发环境详细日志）\nlogging:\n  level:\n    com.example.campusapp: debug\n    org.springframework.security: debug\n\n', '8e543c666ac48770eb815ffb76473261', '2026-02-28 15:19:00', '2026-02-28 15:19:01', 'nacos', '172.18.0.1', 'U', 'public', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');
